{
    // =========================================================
    //  settings.json  ―  VS Code の「設定ファイル」
    // =========================================================
    // ここに書いた設定は、このワークスペース（フォルダ）を
    // VS Code で開いたときだけ有効になる。
    // 個人のグローバル設定を上書き(オーバーライド)できる。
    // ---------------------------------------------------------

    // ---- ファイルのエンコーディング（文字コード） ----
    // このプロジェクトは Shift_JIS / CP932 のファイルが多いので
    // デフォルトを Shift_JIS にしておく->#todo すべてのファイルをcp932, CRLFに強制する.
    "files.encoding": "cp932",


    // 「BOM 付き UTF-8 かどうか」を自動判定してくれる
    "files.autoGuessEncoding": true,

    // ---- 改行コード ----
    // Windows プロジェクトなので CRLF（\r\n）を#todo必須にする
    "files.eol": "\r\n",

    // ---- 保存時の自動整形 ----
    // ファイル末尾に必ず空行を1つ入れる（Git diff がきれいになる）
    "files.insertFinalNewline": true,
    // 末尾の無駄な空白を自動削除
    "files.trimTrailingWhitespace": true,

    // ---- 検索・エクスプローラーから除外するフォルダ ----
    // ビルド成果物や中間ファイルのフォルダを非表示にして
    // サイドバーや検索結果をスッキリさせる
    "files.exclude": {
        "**/.vs": true,
        "**/.git": true,
        "**/obj": true,
        "**/bin": true,
        "**/x64/Debug": true,
        "**/x64/Release": true,
        "**/*.suo": true,
        "**/*.user": true
    },

    // 検索時に無視するフォルダ（上とは別に指定できる）
    "search.exclude": {
        "**/obj": true,
        "**/bin": true,
        "**/x64": true,
        "**/.vs": true,
        "**/Debug": true,
        "**/Release": true,
        "**/*.dll": true,
        "**/*.exe": true,
        "**/*.pdb": true
    },

    // ---- タブとインデント ----
    // C/C++ は タブ文字（\t）を使うことが多い
    // 1つのタブの表示幅 = スペース4個分
    "editor.tabSize": 4,
    "editor.detectIndentation": true,

    // ---- エディタの見た目 ----
    // 1行あたりの目安線（ガイドライン）を120文字目に表示
    "editor.rulers": [120],

    // ---- Git 関連 ----
    // 変更があったファイルをエクスプローラーで色付きで表示
    "git.decorations.enabled": true,
}

"""pre-commit hook: 全追跡ファイルを denylist パターンでスキャンする."""

import os
import re
import subprocess
import sys


def load_denylist(path: str) -> list[tuple[str, re.Pattern]]:
    """denylist ファイルからパターンを読み込む.

    Returns:
        [(raw_pattern, compiled_regex), ...]
    """
    if not os.path.isfile(path):
        raise RuntimeError(f"denylist file not found: {path}")

    patterns = []
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line or line.startswith("#"):
                continue
            patterns.append((line, re.compile(line)))
    return patterns


def tracked_files() -> list[str]:
    """git ls-files で全追跡ファイルを返す."""
    result = subprocess.run(
        ["git", "ls-files", "-z"],
        capture_output=True,
    )
    if result.returncode != 0:
        raise RuntimeError(f"git ls-files failed: {result.stderr.decode()}")
    raw = result.stdout
    if not raw:
        return []
    return [p for p in raw.decode("utf-8").split("\0") if p]


def is_binary(data: bytes) -> bool:
    """先頭 512 byte に null byte があればバイナリ."""
    return b"\x00" in data[:512]


def scan_file(
    filepath: str,
    combined: re.Pattern,
    patterns: list[tuple[str, re.Pattern]],
) -> list[tuple[int, str, str]]:
    """ファイルをスキャンして違反を返す.

    Returns:
        [(line_number, line_content, pattern_str), ...]
    """
    try:
        data = open(filepath, "rb").read()
    except OSError:
        return []

    if not data or is_binary(data):
        return []

    # デコード: cp932 → utf-8 → latin-1 フォールバック
    text = None
    for enc in ("cp932", "utf-8"):
        try:
            text = data.decode(enc)
            break
        except (UnicodeDecodeError, ValueError):
            continue
    if text is None:
        text = data.decode("latin-1")

    violations = []
    for lineno, line in enumerate(text.splitlines(), start=1):
        if not combined.search(line):
            continue
        for raw, pat in patterns:
            if pat.search(line):
                violations.append((lineno, line.rstrip(), raw))

    return violations


def main() -> int:
    hooks_dir = os.path.dirname(os.path.abspath(__file__))
    denylist_path = os.path.join(hooks_dir, ".denylist")

    patterns = load_denylist(denylist_path)
    if not patterns:
        print("  denylist is empty, skipping.")
        return 0

    # combined pattern で高速プリスクリーン
    combined_raw = "|".join(f"(?:{raw})" for raw, _ in patterns)
    combined = re.compile(combined_raw)

    files = tracked_files()
    if not files:
        print("  no tracked files.")
        return 0

    # ファイル別に違反を集約
    all_violations: dict[str, list[tuple[int, str, str]]] = {}
    for f in files:
        if not os.path.isfile(f):
            continue
        hits = scan_file(f, combined, patterns)
        if hits:
            all_violations[f] = hits

    if not all_violations:
        print("  no denylist violations found.")
        return 0

    # レポート
    total = sum(len(v) for v in all_violations.values())
    print(f"\nDENYLIST: {total} violation(s) in {len(all_violations)} file(s):\n")
    for filepath, hits in sorted(all_violations.items()):
        print(f"  {filepath}:")
        for lineno, line, pat in hits:
            # 行が長すぎる場合は切り詰め
            display = line if len(line) <= 120 else line[:117] + "..."
            print(f"    L{lineno}: [{pat}] {display}")
        print()

    return 1


if __name__ == "__main__":
    sys.exit(main())

